import{_ as e,c as t,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"FAQ: 故障排查 | opencode-md-table-formatter","description":"学习 opencode-md-table-formatter 插件的常见问题和故障排查方法。快速定位表格格式化问题，解决配置、结构、对齐等疑难杂症。","frontmatter":{"title":"FAQ: 故障排查 | opencode-md-table-formatter","sidebarTitle":"遇到问题怎么办","subtitle":"FAQ: 故障排查 | opencode-md-table-formatter","description":"学习 opencode-md-table-formatter 插件的常见问题和故障排查方法。快速定位表格格式化问题，解决配置、结构、对齐等疑难杂症。","order":3},"headers":[],"relativePath":"zh/franlol/opencode-md-table-formatter/faq/index.md","filePath":"zh/franlol/opencode-md-table-formatter/faq/index.md"}'),l={name:"zh/franlol/opencode-md-table-formatter/faq/index.md"};function i(n,a,d,s,h,c){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="章节概述" tabindex="-1">章节概述 <a class="header-anchor" href="#章节概述" aria-label="Permalink to &quot;章节概述&quot;">​</a></h2><p>本章节涵盖 opencode-md-table-formatter 插件的常见问题和故障排查方法，帮助你快速定位和解决表格格式化过程中遇到的各种问题。</p><hr><h2 id="子页面导航" tabindex="-1">子页面导航 <a class="header-anchor" href="#子页面导航" aria-label="Permalink to &quot;子页面导航&quot;">​</a></h2><h3 id="常见问题-表格没格式化怎么办" tabindex="-1"><a href="./troubleshooting/">常见问题：表格没格式化怎么办</a> <a class="header-anchor" href="#常见问题-表格没格式化怎么办" aria-label="Permalink to &quot;[常见问题：表格没格式化怎么办](troubleshooting/)&quot;">​</a></h3><p>全面介绍插件使用中的常见问题和解决方案：</p><ul><li><strong>表格不格式化</strong>：检查配置、版本要求、重启 OpenCode</li><li><strong>无效表格结构</strong>：理解 &quot;invalid structure&quot; 错误含义，学习正确表格语法</li><li><strong>格式化失败</strong>：处理 &quot;table formatting failed&quot; 错误和异常情况</li><li><strong>不支持的表格类型</strong>：了解 HTML 表格、多行单元格等限制场景</li><li><strong>格式化后不对齐</strong>：排查隐藏模式、单元格超长、行内代码等问题</li></ul><hr><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to &quot;学习路径建议&quot;">​</a></h2><p>建议在完成 <a href="./../start/features/">功能全览</a> 后，遇到实际问题时查阅本章节，或作为问题排查的参考手册。</p><p>你可以按照以下顺序学习：</p><ol><li><strong>遇到问题时</strong>：先根据症状定位问题类型（表格不格式化、报错信息等）</li><li><strong>按步骤排查</strong>：按照故障排查指南的检查清单逐一验证</li><li><strong>深入理解</strong>：阅读<a href="./../advanced/table-spec/">表格规范</a>和<a href="./../advanced/concealment-mode/">隐藏模式原理</a>了解技术细节</li><li><strong>已知限制</strong>：查看<a href="./../appendix/limitations/">已知限制</a>了解插件边界</li></ol><hr><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>学习本章节前，建议先完成：</p><ul><li>✅ <a href="./../start/getting-started/">一分钟上手：安装与配置</a> - 了解如何安装和配置插件</li><li>✅ <a href="./../start/features/">功能全览：自动格式化的魔法</a> - 理解插件的核心功能和工作原理</li></ul><p>同时，你应该具备：</p><ul><li>熟悉 Markdown 表格的基本语法</li><li>了解 OpenCode 的插件配置方式（<code>opencode.jsonc</code>）</li></ul><hr><h2 id="下一步指引" tabindex="-1">下一步指引 <a class="header-anchor" href="#下一步指引" aria-label="Permalink to &quot;下一步指引&quot;">​</a></h2><p>完成本章节后，你可以继续学习：</p><ul><li><p><strong>进阶知识</strong>：</p><ul><li><a href="./../advanced/table-spec/">表格规范：什么样的表格能被格式化</a> - 掌握有效表格的结构要求</li><li><a href="./../advanced/concealment-mode/">隐藏模式原理：为什么宽度计算如此重要</a> - 理解 OpenCode 隐藏模式的工作原理</li><li><a href="./../advanced/alignment/">对齐方式详解：左对齐、居中、右对齐</a> - 掌握三种对齐方式的语法和效果</li></ul></li><li><p><strong>技术细节</strong>：</p><ul><li><a href="./../appendix/limitations/">已知限制：插件的边界在哪里</a> - 了解插件的已知限制和不适用的场景</li><li><a href="./../appendix/tech-details/">技术细节：缓存机制与性能优化</a> - 了解插件的内部缓存机制和性能优化策略</li></ul></li></ul><hr>',24)])])}const m=e(l,[["render",i]]);export{f as __pageData,m as default};
